Here's a C++ function that takes a reference to a `std::string` containing markdown formatted text and returns a `std::string` containing HTML formatted text using the Boost.Markdown library.
```cpp
#include <string>
#include <boost/markdown.hpp>
#include <iostream>

std::string convertMarkdownToHtml(std::string markdownString) {
    std::string htmlString;

    boost::markdown::MarkdownConverter converter;
    boost::markdown::ast::MarkdownParseException::handler handler = [] (boost::markdown::ast::MarkdownParseException& e) {
        std::cerr << "Error in input string at offset " << e.offset << ": " << e.what() << std::endl;
        htmlString = "";
        return;
    };

    try {
        boost::markdown::MarkdownDocument doc(converter, handler);
        doc.replace_html_block(markdownString);
        htmlString = doc.document_tree()->html_text();
    } catch (const boost::markdown::ast::MarkdownParseException& e) {
        std::cerr << "Error in input string at offset " << e.offset << ": " << e.what() << std::endl;
        htmlString = "";
    }

    return htmlString;
}

int main() {
    std::string input = "# Hello, World!\n\n* This is a heading\n\nThis is a paragraph";
    std::string output = convertMarkdownToHtml(input);

    std::cout << "Markdown: " << input << std::endl;
    std::cout << "HTML:    " << output << std::endl;

    return 0;
}
```
The `convertMarkdownToHtml` function uses the Boost.Markdown library to parse the input string and convert it to HTML. The resulting HTML string is then returned.

In the main function, a sample markdown string is provided and the resulting HTML string is outputted for comparison.

